void BatchModifyParameter::dialogShown_cb()
{
	PropertyList* double012Props = doubleJingeilv->GetProperties();
	double012Props->SetDouble("Value", 0);
	delete double012Props;

	PropertyList* double0121Props = doubleZhuanshu->GetProperties();
	double0121Props->SetDouble("Value", 0);
	delete double0121Props;

	PropertyList* double0122Props = doubleYuliang->GetProperties();
	double0122Props->SetDouble("Value", 0);
	delete double0122Props;

    try
    {
		//获取加工设置的TAG
		tag_t setup_tag = NULL_TAG;
		UF_SETUP_ask_setup(&setup_tag);
		if (setup_tag == NULL_TAG)
		{
			uc1601("请先初始化加工环境", 1);
			return;
		}

		//获得程序视图下的根节点
		tag_t programRootgroup = NULL_TAG;
		UF_SETUP_ask_program_root(setup_tag, &programRootgroup);

		//递归方式获得所有的toolTAG
		vector<tag_t> vToolTags;
		
		GetAllToolTag2(programRootgroup, vToolTags);
		vector<NXOpen::NXString> vAllToolNames;
		vector<string> vToolNames;
		for (int i = 0; i < vToolTags.size(); i++)
		{
			char name[500];
			UF_OBJ_ask_name(vToolTags[i], name);
			vAllToolNames.push_back(name);
			
		}
		enum0->SetEnumMembers(vAllToolNames);
    }
    catch(exception& ex)
    {
        BatchModifyParameter::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
}

