int BatchModifyParameter::ok_cb()
{
    int errorCode = 0;
    try
    {
		

		double jingheilv = doubleJingeilv->Value();
		double zhuanshu = doubleZhuanshu->Value();
		double yuliang = doubleYuliang->Value();
		

		tag_t setup_tag = NULL_TAG;
		UF_SETUP_ask_setup(&setup_tag);

		
		tag_t mctRootgroup = NULL_TAG;
		UF_SETUP_ask_mct_root(setup_tag, &mctRootgroup);
		tag_t toolTag = NULL_TAG;

		string strToolName = enum0->ValueAsString().GetLocaleText();
		const char* ToolName1 = nullptr;
		ToolName1 = strToolName.c_str();
		
		char* ToolName = nullptr;                       //初始化char*类型
		ToolName = const_cast<char*>(ToolName1);           //const char*类型转char*类型

	
		
		UF_NCGROUP_ask_object_of_name(mctRootgroup, ToolName, &toolTag);
		
		int count = 0;
		tag_t * objects;
		UF_UI_ONT_ask_selected_nodes(&count, &objects);
		for (int i = 0; i<count; i++)
		{
			tag_t operTag = objects[i];
			int type = 0, subtype = 0;
			UF_OBJ_ask_type_and_subtype(operTag, &type, &subtype);
			if (type == UF_machining_operation_type)
			{
				UF_NCGROUP_accept_member(toolTag, objects[i]);
				
				if (zhuanshu != 0)
				{
					UF_PARAM_set_double_value(objects[i], UF_PARAM_SPINDLE_RPM, zhuanshu);
				}

				if (jingheilv != 0)
				{
					//设置进给率
					UF_PARAM_feedrate_t feed_value;
					UF_PARAM_ask_subobj_ptr_value(objects[i], UF_PARAM_FEED_CUT, &feed_value);
					feed_value.value = jingheilv;
					UF_PARAM_set_subobj_ptr_value(objects[i], UF_PARAM_FEED_CUT, &feed_value);
				}

				if (yuliang != 0)
				{
					//设置部件余量
					UF_PARAM_set_double_value(objects[i], UF_PARAM_STOCK_PART, yuliang);
				}

				
			}
			
			UF_UI_ONT_refresh();
			//uc1601("完成参数批修改！", 1);
		}

    }
    catch(exception& ex)
    {
        errorCode = 1;
        BatchModifyParameter::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}


