void BatchModifyParameter::GetAllToolTag2(tag_t groupTag, vector<tag_t> &vToolTags)
{
	std::vector<tag_t>tool_tag;
	tag_t ObjectTag = NULL_TAG;
	int Type, SubType;
	UF_OBJ_cycle_objs_in_part(UF_PART_ask_display_part(), UF_machining_tool_type, &ObjectTag);
	while (ObjectTag != NULL_TAG)
	{
		UF_OBJ_ask_extended_type_and_subtype(ObjectTag, &Type, &SubType);
		if (Type == UF_machining_tool_type&&SubType == UF_mach_tool_subtype)
		{
			vToolTags.push_back(ObjectTag);
		}
		UF_OBJ_cycle_objs_in_part(UF_PART_ask_display_part(), UF_machining_tool_type, &ObjectTag);
	}

}
